// 解析輸入參數
const year = $json.year || new Date().getFullYear();
const month = $json.month || new Date().getMonth() + 1;
const queryType = $json.queryType || 'details'; // 'details' 或 'summary'
const category = $json.category || null;

// 建立 spreadsheet mapping
// TODO: 之後可以改成從環境變數或 Redis 讀取
const sheetMappings = {
  '2026-1': { id: process.env.EXPENSE_SHEET_2026_01 || '1WwTVhPS-sDxDBl98ZuleCyNP2vmCcV5zV4ZykvgLE0g' },
  '2026-2': { id: process.env.EXPENSE_SHEET_2026_02 || '15FVJ81u0RsLCrVs3ZRxekxaPsjcAet9bUXe2zhcS3SE' },
  '2026-3': { id: process.env.EXPENSE_SHEET_2026_03 || '17KNSH-qunxh0TFf_No-mAE1vr40QYcZ_qT75GoSJEqs' },
  // 繼續添加其他月份...
};

const key = `${year}-${month}`;
const config = sheetMappings[key];

if (!config) {
  throw new Error(`找不到 ${year} 年 ${month} 月的帳本`);
}

// 決定要讀取的 sheet 名稱
const sheetName = queryType === 'summary' ? '開支總結' : '開支一覽';

return {
  spreadsheetId: config.id,
  sheetName: sheetName,
  documentName: `${year} ${month}月 開支清單`,
  category: category,
  year: year,
  month: month,
  queryType: queryType
};

// 處理讀取到的資料
const items = $input.all();
const category = $('Parse and Route').first().json.category;
const queryType = $('Parse and Route').first().json.queryType;
const year = $('Parse and Route').first().json.year;
const month = $('Parse and Route').first().json.month;

let result = [];

if (queryType === 'details') {
  // 處理「開支一覽」的資料
  result = items.map(item => ({
    日期: item.json.日期 || item.json['Date'],
    項目: item.json.項目 || item.json['Item'],
    分類: item.json.分類 || item.json['Category'],
    金額: item.json.金額 || item.json['Amount'],
    幣值: item.json.幣值 || item.json['Currency'] || 'TWD',
    備註: item.json.備註 || item.json['Note'] || ''
  }));

  // 如果有指定分類，進行篩選
  if (category) {
    result = result.filter(item => 
      item.分類 && item.分類.includes(category)
    );
  }

  // 計算總金額
  const totalByCategory = {};
  const totalByCurrency = {};

  result.forEach(item => {
    const cat = item.分類 || '未分類';
    const currency = item.幣值 || 'TWD';
    const amount = parseFloat(item.金額) || 0;

    if (!totalByCategory[cat]) {
      totalByCategory[cat] = {};
    }
    if (!totalByCategory[cat][currency]) {
      totalByCategory[cat][currency] = 0;
    }
    totalByCategory[cat][currency] += amount;

    if (!totalByCurrency[currency]) {
      totalByCurrency[currency] = 0;
    }
    totalByCurrency[currency] += amount;
  });

  return [{
    json: {
      year: year,
      month: month,
      queryType: 'details',
      category: category,
      recordCount: result.length,
      records: result,
      totalByCategory: totalByCategory,
      totalByCurrency: totalByCurrency
    }
  }];

} else {
  // 處理「開支總結」的資料
  result = items.map(item => ({
    分類: item.json.分類 || item.json['Category'],
    TWD: item.json.TWD || 0,
    JPY: item.json.JPY || 0,
    USD: item.json.USD || 0,
    小計TWD: item.json['小計(TWD)'] || item.json['Subtotal (TWD)'] || 0
  }));

  // 如果有指定分類，進行篩選
  if (category) {
    result = result.filter(item => 
      item.分類 && item.分類.includes(category)
    );
  }

  return [{
    json: {
      year: year,
      month: month,
      queryType: 'summary',
      category: category,
      summary: result
    }
  }];
}
